515	For us, the canonical example is a 2-affine open cover $X_4 = U_2 \cup U_3$ of an open $X_4 \subseteq C.\mathrm{left}.\mathrm{toTopCat}$ on a curve $C$, with $U_1 = U_2 \cap U_3$. After iter-017 + iter-018 + iter-019 land the LES theorem, this specialisation will be the engine of the Path-2 Serre-finiteness argument (`iter-020+`).
516	
517	\subsection{First LES building block: the sum of two restriction maps}
518	
519	\begin{definition}[Sum of two restriction maps in MV cohomology, $\HModulePrime$ flavor (iter-017)]
520	  \label{def:Scheme_HModule_prime_toBiprod}
521	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod}
522	  \leanok
523	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
524	  Let $k$ be a field, $C$ a category with $J : \mathrm{GrothendieckTopology}\,C$, and assume $\HasWeakSheafify\,J\,(\mathrm{Type}\,u)$, $\HasSheafify\,J\,(\ModuleCat.\{u\}\,k)$, and $\HasExt(\Sheaf(J, \ModuleCat.\{u\}\,k))$. Let $S : J.\MayerVietorisSquare$, $F : \Sheaf(J, \ModuleCat.\{u\}\,k)$, and $n : \mathbb N$. Define
525	  \[
526	    \HModulePrime\_\toBiprod\,k\,S\,F\,n \;\colon\;
527	    (\HModulePrime\_\cohomologyPresheaf\,k\,F\,n).\mathrm{obj}\,(\mathrm{op}\,S.X_4)
528	    \longrightarrow
529	    (\HModulePrime\_\cohomologyPresheaf\,k\,F\,n).\mathrm{obj}\,(\mathrm{op}\,S.X_2)
530	    \boxplus
531	    (\HModulePrime\_\cohomologyPresheaf\,k\,F\,n).\mathrm{obj}\,(\mathrm{op}\,S.X_3)
532	  \]
533	  by
534	  \[
535	    \HModulePrime\_\toBiprod\,k\,S\,F\,n \;:=\;
536	      \mathrm{biprod.lift}\bigl((\HModulePrime\_\cohomologyPresheaf\,k\,F\,n).\mathrm{map}\,S.f_{2,4}.\mathtt{op},\;\;(\HModulePrime\_\cohomologyPresheaf\,k\,F\,n).\mathrm{map}\,S.f_{3,4}.\mathtt{op}\bigr).
537	  \]
538	\end{definition}
539	
540	\begin{proof}
541	  \leanok
542	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf}
543	  Direct mirror of Mathlib's $\mathtt{GrothendieckTopology.MayerVietorisSquare.toBiprod}$ (\texttt{MayerVietoris.lean} L43--46) with $F.\cohomologyPresheaf \rightarrow \HModulePrime\_\cohomologyPresheaf\,k\,F$. The biproduct $\boxplus$ is the standard biproduct in $\AddCommGrpCat$ (Mathlib `Mathlib/Algebra/Category/Grp/Biproducts.lean`); it is well-defined because $\AddCommGrpCat$ has finite biproducts.
544	  Plan-agent \texttt{lean\_run\_code} probe (iter-017) confirms the body typechecks end-to-end against current Mathlib + post-iter-016 project state, kernel-only axioms (\lstinline{propext}, \lstinline{Classical.choice}, \lstinline{Quot.sound}). The closure body is the one-line term \lstinline{biprod.lift ((HModule'_cohomologyPresheaf k F n).map S.f₂₄.op) ((HModule'_cohomologyPresheaf k F n).map S.f₃₄.op)}.
545	\end{proof}
546	
547	\subsection{Second LES building block: the difference of two restriction maps}
548	
549	\begin{definition}[Difference of two restriction maps in MV cohomology, $\HModulePrime$ flavor (iter-017)]
550	  \label{def:Scheme_HModule_prime_fromBiprod}
551	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod}
552	  \leanok
553	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
554	  In the setting of Definition~\ref{def:Scheme_HModule_prime_toBiprod}, define
555	  \[
556	    \HModulePrime\_\fromBiprod\,k\,S\,F\,n \;\colon\;
557	    (\HModulePrime\_\cohomologyPresheaf\,k\,F\,n).\mathrm{obj}\,(\mathrm{op}\,S.X_2)
558	    \boxplus
559	    (\HModulePrime\_\cohomologyPresheaf\,k\,F\,n).\mathrm{obj}\,(\mathrm{op}\,S.X_3)
560	    \longrightarrow
561	    (\HModulePrime\_\cohomologyPresheaf\,k\,F\,n).\mathrm{obj}\,(\mathrm{op}\,S.X_1)
562	  \]
563	  by
564	  \[
565	    \HModulePrime\_\fromBiprod\,k\,S\,F\,n \;:=\;
566	      \mathrm{biprod.desc}\bigl((\HModulePrime\_\cohomologyPresheaf\,k\,F\,n).\mathrm{map}\,S.f_{1,2}.\mathtt{op},\;\;-(\HModulePrime\_\cohomologyPresheaf\,k\,F\,n).\mathrm{map}\,S.f_{1,3}.\mathtt{op}\bigr).
567	  \]
568	\end{definition}
569	
570	\begin{proof}
571	  \leanok
572	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf}
573	  Direct mirror of Mathlib's $\mathtt{GrothendieckTopology.MayerVietorisSquare.fromBiprod}$ (\texttt{MayerVietoris.lean} L67--70) with $F.\cohomologyPresheaf \rightarrow \HModulePrime\_\cohomologyPresheaf\,k\,F$. The negation $-(\HModulePrime\_\cohomologyPresheaf\,k\,F\,n).\mathrm{map}\,S.f_{1,3}.\mathtt{op}$ is the additive inverse in the additive structure of $\AddCommGrpCat$-morphisms (the codomain category is $\AddCommGrpCat$ which is preadditive, so morphisms have additive inverses); the sign is the standard convention from the Mayer-Vietoris LES, encoding the alternating-sum structure of the Čech complex.
574	  Plan-agent \texttt{lean\_run\_code} probe (iter-017) confirms the body typechecks end-to-end against current Mathlib + post-iter-016 project state, kernel-only axioms. The closure body is the one-line term \lstinline{biprod.desc ((HModule'_cohomologyPresheaf k F n).map S.f₁₂.op) (-(HModule'_cohomologyPresheaf k F n).map S.f₁₃.op)}.
575	\end{proof}
576	
577	\begin{remark}[Why these are the iter-017 targets]
578	  The Mayer-Vietoris LES theorem (Mathlib \texttt{MayerVietoris.lean} L120--141) constructs a six-term sequence
579	  \[
580	    \cdots \longrightarrow H^n(S.X_4, F) \xrightarrow{\;\toBiprod\;} H^n(S.X_2, F) \boxplus H^n(S.X_3, F) \xrightarrow{\;\fromBiprod\;} H^n(S.X_1, F) \xrightarrow{\;\delta\;} H^{n+1}(S.X_4, F) \longrightarrow \cdots
581	  \]
582	  whose three building blocks are $\toBiprod$, $\fromBiprod$, and the connecting hom $\delta$. The first two are direct one-line term-mode \texttt{biprod.lift} / \texttt{biprod.desc} bodies on the cohomology presheaf's restriction maps; iter-017 lands them. Iter-018 proves the composition-is-zero lemma $\toBiprod \circ \fromBiprod = 0$ (Mathlib L72--75) — the verbatim Mathlib \lstinline{simp only} proof transfers cleanly because every rewrite step is value-category-agnostic (see Section~\ref{sec:hmodule_prime_mayer_vietoris_compose_zero}). The connecting hom $\delta$ requires the extension class machinery \lstinline{Ext.precomp} (Mathlib \texttt{Mathlib/Algebra/Homology/DerivedCategory/Ext/ExactSequences.lean}) applied to the Mayer-Vietoris square's induced short exact sequence; iter-019+ will scope it because Mathlib's \lstinline{MayerVietorisSquare.shortComplex_shortExact} (Mathlib \texttt{Mathlib/CategoryTheory/Sites/MayerVietorisSquare.lean} L240--268) is built from \lstinline{AddCommGrpCat.free}-yoneda — the $\ModuleCat\,k$ flavour requires a parallel construction with \lstinline{ModuleCat.free k}-yoneda, which is substantive multi-iteration work. Iter-019/020+ then lands the LES sequence itself, the iso to $\Ext.\mathrm{contravariantSequence}$ (Mathlib L120--141), and the exactness theorem.
583	\end{remark}
584	
585	\begin{remark}[Compatibility with Mathlib's $\AddCommGrpCat$-flavored LES]
586	  By construction, the codomain $\AddCommGrpCat$ of $\HModulePrime\_\cohomologyPresheaf$ matches Mathlib's $F.\cohomologyPresheaf$ codomain (forced by $\Abelian.\extFunctor\,n$ always landing in $\AddCommGrpCat$). The biproduct $\boxplus$ in $\AddCommGrpCat$, the morphism additive structure, and the negation are all the same in both worlds. The only difference is the source of the cohomology presheaf: $F : \Sheaf\,J\,\AddCommGrpCat$ in Mathlib vs.\ $F : \Sheaf\,J\,(\ModuleCat.\{u\}\,k)$ in our setup. In particular, every Mathlib-level proof on $\toBiprod$ / $\fromBiprod$ (e.g.\ the composition-is-zero lemma at L72--75) transports verbatim to our setting once we replace `F.cohomologyPresheaf` with `HModule'_cohomologyPresheaf k F`; iter-018 uses this directly (Section~\ref{sec:hmodule_prime_mayer_vietoris_compose_zero}).
587	\end{remark}
